import org.mockito.MockitoAnnotations
import org.wordpress.android.fluxc.store.PostStore
import org.wordpress.android.util.LocaleManagerWrapper

/**
 * Test to verify that EditPostRepository handles null post gracefully,
 * particularly for the dateCreated property which was causing NPE.
 */
class EditPostRepositoryNullPostTest {
    @Mock
    private lateinit var localeManagerWrapper: LocaleManagerWrapper

    @Mock
    private lateinit var postStore: PostStore

    @Mock
    private lateinit var postUtils: PostUtilsWrapper

    private lateinit var repository: EditPostRepository

    @Before
    fun setUp() {
        MockitoAnnotations.openMocks(this)
        repository = EditPostRepository(
            localeManagerWrapper = localeManagerWrapper,
            postStore = postStore,
            postUtils = postUtils,
            mainDispatcher = Dispatchers.Unconfined,
            bgDispatcher = Dispatchers.Unconfined
        )
    }

    @Test
    fun `dateCreated returns empty string when post is null`() {
        // Given: repository with no post loaded (post is null by default)

        // When: accessing dateCreated property
        val dateCreated = repository.dateCreated

        // Then: should return empty string instead of throwing NPE
        assertEquals("", dateCreated)
    }
}
"}

